#!/usr/bin/env bash
# post-commit-template.sh
# This file is copied into .git/hooks/post-commit in each companion project.
# It appends a commit-event YAML file to the KM vault's pending queue.
#
# DO NOT EDIT THIS FILE DIRECTLY IN A PROJECT'S .git/hooks/ —
# edit the master copy at c:/Projects/Knowledge-Management/scripts/post-commit-template.sh
# and re-run install-hooks.sh to propagate changes.

# ── Configuration ────────────────────────────────────────────────────────────

KM_VAULT="c:/Projects/Knowledge-Management/vault"
PENDING_DIR="$KM_VAULT/transcripts/commits/pending"

# ── Abort if vault doesn't exist ─────────────────────────────────────────────

if [ ! -d "$PENDING_DIR" ]; then
  # Vault not found — skip silently so we don't break the commit workflow
  exit 0
fi

# ── Gather commit information ────────────────────────────────────────────────

PROJECT_NAME=$(basename "$(git rev-parse --show-toplevel 2>/dev/null)" 2>/dev/null || echo "unknown")
COMMIT_HASH=$(git rev-parse --short HEAD 2>/dev/null || echo "unknown")
COMMIT_DATE=$(date "+%Y-%m-%d %H:%M")
COMMIT_AUTHOR=$(git log -1 --format="%an" 2>/dev/null || echo "unknown")
COMMIT_MESSAGE=$(git log -1 --format="%s" 2>/dev/null || echo "")

# Determine conventional commit type from message prefix
CONVENTIONAL_TYPE="chore"
case "$COMMIT_MESSAGE" in
  feat:*)     CONVENTIONAL_TYPE="feat" ;;
  fix:*)      CONVENTIONAL_TYPE="fix" ;;
  docs:*)     CONVENTIONAL_TYPE="docs" ;;
  adr:*)      CONVENTIONAL_TYPE="adr" ;;
  refactor:*) CONVENTIONAL_TYPE="refactor" ;;
  test:*)     CONVENTIONAL_TYPE="test" ;;
  chore:*)    CONVENTIONAL_TYPE="chore" ;;
esac

# Get list of changed files (max 20 to keep the event file readable)
CHANGED_FILES=$(git diff-tree --no-commit-id -r --name-only HEAD 2>/dev/null | head -20)

# ── Build the event file ─────────────────────────────────────────────────────

TIMESTAMP=$(date "+%Y%m%d-%H%M%S")
EVENT_FILE="$PENDING_DIR/${TIMESTAMP}-${PROJECT_NAME}-${COMMIT_HASH}.yaml"

{
  echo "---"
  echo "source: \"$PROJECT_NAME\""
  echo "commit: \"$COMMIT_HASH\""
  echo "date: \"$COMMIT_DATE\""
  echo "author: \"$COMMIT_AUTHOR\""
  echo "message: \"$(echo "$COMMIT_MESSAGE" | sed 's/"/\\"/g')\""
  echo "conventional_type: $CONVENTIONAL_TYPE"
  echo "changed_files:"
  while IFS= read -r f; do
    [ -n "$f" ] && echo "  - $f"
  done <<< "$CHANGED_FILES"
  echo "status: pending"
  echo "---"
} > "$EVENT_FILE"

# ── Done ─────────────────────────────────────────────────────────────────────
# No output — post-commit hooks should be silent unless there's an error
exit 0
